    14→fn parse<T, F>(f: F, s: &'static str) -> Result<T, ParseError<'static>>
    15→where
    16→    F: for<'t> Fn(&ParserContext, &mut Parser<'static, 't>) -> Result<T, ParseError<'static>>,
    17→{
    18→    let mut input = ParserInput::new(s);
    19→    parse_input(f, &mut input)
    20→}
    21→
    22→fn parse_input<'i: 't, 't, T, F>(f: F, input: &'t mut ParserInput<'i>) -> Result<T, ParseError<'i>>
    23→where
    24→    F: Fn(&ParserContext, &mut Parser<'i, 't>) -> Result<T, ParseError<'i>>,
    25→{
    26→    let url_data = Url::parse("http://localhost").unwrap().into();
    27→    let context = ParserContext::new(
    28→        Origin::Author,
    29→        &url_data,
    30→        Some(CssRuleType::Style),
    31→        ParsingMode::DEFAULT,
    32→        QuirksMode::NoQuirks,
    33→        /* namespaces = */ Default::default(),
    34→        None,
    35→        None,
    36→    );
    37→    let mut parser = Parser::new(input);
    38→    f(&context, &mut parser)
    39→}
    40→
    41→// This is a macro so that the file/line information
    42→// is preserved in the panic
    43→macro_rules! assert_roundtrip_with_context {
    44→    ($fun:expr, $string:expr) => {
    45→        assert_roundtrip_with_context!($fun, $string, $string);
    46→    };
    47→    ($fun:expr, $input:expr, $output:expr) => {{
    48→        let mut input = ::cssparser::ParserInput::new($input);
    49→        let serialized = super::parse_input(
    50→            |context, i| {
    51→                let parsed = $fun(context, i).expect(&format!("Failed to parse {}", $input));
    52→                let serialized = ToCss::to_css_string(&parsed);
    53→                assert_eq!(serialized, $output);
    54→                Ok(serialized)
    55→            },
    56→            &mut input,
    57→        )
    58→        .unwrap();
    59→
    60→        let mut input = ::cssparser::ParserInput::new(&serialized);
    61→        let unwrapped = super::parse_input(
    62→            |context, i| {
    63→                let re_parsed =
    64→                    $fun(context, i).expect(&format!("Failed to parse serialization {}", $input));
    65→                let re_serialized = ToCss::to_css_string(&re_parsed);
    66→                assert_eq!(serialized, re_serialized);
    67→                Ok(())
    68→            },
    69→            &mut input,
    70→        )
    71→        .unwrap();
    72→        unwrapped
    73→    }};
    74→}
